class Solution {
    public int numberOfArrays(String s, int k) {
        long mod = 1000000007;
        int count = 0;
        for (int i = 0; i < s.length(); i++) {
            long num = 0;
            for (int j = i; j < s.length(); j++) {
                num = num * 10 + (s.charAt(j) - '0');
                if (num <= k) {
                    count = (count + 1) % mod;
                }
            }
        }
        return count;
    }
}
